package ru.nsu.tumilevich;import org.junit.jupiter.api.AfterEach;import org.junit.jupiter.api.BeforeEach;import org.junit.jupiter.api.Test;import java.io.File;import java.util.List;import static org.junit.jupiter.api.Assertions.*;class PizzeriaEngineTest {	private PizzeriaConfig config;	@BeforeEach	void setUp() {		config = new PizzeriaConfig();		config.setStockCapacity(5);		PizzeriaConfig.BakerConfig bakerConf = new PizzeriaConfig.BakerConfig();		bakerConf.setCookingTime(5000);		config.setBakers(List.of(bakerConf));		PizzeriaConfig.CourierConfig courierConf = new PizzeriaConfig.CourierConfig();		courierConf.setDeliveryTime(5000);		courierConf.setTrunkCapacity(2);		config.setCouriers(List.of(courierConf));	}	@AfterEach	void cleanUp() {		File f = new File("unfinished_orders.ser");		if (f.exists()) {			f.delete();		}	}	@Test	void testEngineSaveAndLoadUnfinishedOrders() throws InterruptedException {		PizzeriaEngine engine1 = new PizzeriaEngine(config);		engine1.start();		engine1.addNewOrder(10);		Thread.sleep(200);		engine1.stop();		File file = new File("unfinished_orders.ser");		assertTrue(file.exists(), "Файл сохранения должен быть создан");		PizzeriaEngine engine2 = new PizzeriaEngine(config);		int maxId = engine2.start();		assertEquals(10, maxId, "Движок должен вернуть максимальный ID из восстановленных заказов");		assertFalse(file.exists(), "Файл сохранения должен быть удален после прочтения");		engine2.stop();	}}